// =============================================================================
// lib/pdf/generate-timecard.ts
// Server-side PDF generation for a single timecard using @react-pdf/renderer.
//
// Layout:
//   - Header:        Norwich Public Schools / TIMECARD / Program name, account, pay period
//   - Staff block:   Name, school, address
//   - Hours table:   Date | Time In | Time Out | Total Hours
//   - Signature block: Staff typed name + timestamp; Signee typed name + timestamp
//   - Footer:        Generated by Norwich Public Schools Timesheet System / timestamp
//
// Returns a Buffer suitable for storage (Supabase Storage) or HTTP response.
// =============================================================================

import React from 'react'
import {
  Document,
  Page,
  Text,
  View,
  StyleSheet,
  renderToBuffer,
  Font,
} from '@react-pdf/renderer'
import { format, parseISO } from 'date-fns'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface TimecardEntry {
  work_date: string   // YYYY-MM-DD
  time_in: string     // HH:MM or HH:MM:SS
  time_out: string    // HH:MM or HH:MM:SS
  total_hours: number
}

export interface TimecardPdfData {
  // Program info
  programName: string
  accountNumber: string
  // Pay period info
  payPeriodLabel: string
  payPeriodStart: string  // YYYY-MM-DD
  payPeriodEnd: string    // YYYY-MM-DD
  // Staff info
  staffName: string
  staffSchool: string
  staffAddress: string
  // Time entries
  entries: TimecardEntry[]
  // Signatures
  staffSignature: string | null
  staffSignedAt: string | null    // ISO timestamp
  signeeName: string | null
  signeeSignature: string | null
  signeeSignedAt: string | null   // ISO timestamp
  // NTL rate (optional — shown in footer summary)
  ntlRate?: number | null
  /** Timecard status for display */
  status: 'draft' | 'submitted' | 'signed' | 'reopen_requested' | 'reopened'
}

