// ---------------------------------------------------------------------------
// Formatting helpers
// ---------------------------------------------------------------------------

function fmtDate(iso: string): string {
  try {
    return format(parseISO(iso), 'EEE, MMM d, yyyy')
  } catch {
    return iso
  }
}

function fmtDateShort(iso: string): string {
  try {
    return format(parseISO(iso), 'MMM d, yyyy')
  } catch {
    return iso
  }
}

function fmtTime(t: string): string {
  // Accepts HH:MM or HH:MM:SS → formats as "h:mm AM/PM"
  try {
    const [hStr, mStr] = t.split(':')
    const h = parseInt(hStr, 10)
    const m = parseInt(mStr, 10)
    const ampm = h >= 12 ? 'PM' : 'AM'
    const h12 = h % 12 === 0 ? 12 : h % 12
    return `${h12}:${String(m).padStart(2, '0')} ${ampm}`
  } catch {
    return t
  }
}

function fmtHours(h: number): string {
  return h.toFixed(2)
}

function fmtTimestamp(iso: string | null): string {
  if (!iso) return ''
  try {
    return format(new Date(iso), 'MMM d, yyyy h:mm a')
  } catch {
    return iso
  }
}

function fmtCurrency(amount: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
  }).format(amount)
}

function getStatusColors(status: TimecardPdfData['status']): { bg: string; text: string } {
  switch (status) {
    case 'signed':
      return { bg: colors.statusSignedBg, text: colors.statusSigned }
    case 'submitted':
      return { bg: colors.statusSubmittedBg, text: colors.statusSubmitted }
    default:
      return { bg: colors.statusDraftBg, text: colors.statusDraft }
  }
}

function getStatusLabel(status: TimecardPdfData['status']): string {
  switch (status) {
    case 'draft': return 'Draft'
    case 'submitted': return 'Submitted'
    case 'signed': return 'Signed'
    case 'reopen_requested': return 'Reopen Requested'
    case 'reopened': return 'Reopened'
    default: return status
  }
}

