// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Generates a single timecard PDF and returns it as a Buffer.
 *
 * @param data - All data needed to render the timecard PDF
 * @returns Promise<Buffer> — ready for HTTP response or Supabase Storage upload
 *
 * @example
 * const pdfBuffer = await generateTimecardPdf(timecardData)
 * // In a Route Handler:
 * return new Response(pdfBuffer, {
 *   headers: {
 *     'Content-Type': 'application/pdf',
 *     'Content-Disposition': `attachment; filename="timecard-${staffName}.pdf"`,
 *   },
 * })
 */
export async function generateTimecardPdf(data: TimecardPdfData): Promise<Buffer> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const doc = React.createElement(TimecardDocument, { data }) as any
  const buffer = await renderToBuffer(doc)
  return Buffer.from(buffer)
}

/**
 * Generates a filename for a timecard PDF.
 * Format: timecard_<StaffName>_<PayPeriodLabel>.pdf
 */
export function getTimecardPdfFilename(
  staffName: string,
  payPeriodLabel: string
): string {
  const safeName = staffName.replace(/[^a-zA-Z0-9]/g, '_').replace(/_+/g, '_')
  const safePeriod = payPeriodLabel.replace(/[^a-zA-Z0-9]/g, '_').replace(/_+/g, '_')
  return `timecard_${safeName}_${safePeriod}.pdf`
}
